import { useControlledState } from '@universe-design/react-utilities';
import { useEventCallback } from '../../hooks';
import { isFunction } from '../../util';
import { SelectSearchAction } from '../internal.interface';
import type { SelectOnSearch } from '../internal.interface';

/**
 * @public
 */
export function useSelectInputValue({ searchValue, onSearch }: { searchValue?: string; onSearch?: SelectOnSearch }) {
  const [inputValue, _setInputValue] = useControlledState<string>('', searchValue);

  const setInputValue = useEventCallback(
    (
      v: string,
      meta: {
        action: SelectSearchAction;
      } = {
        action: SelectSearchAction.Input,
      },
    ) => {
      _setInputValue(v, nextInputValue => {
        isFunction(onSearch) && onSearch(nextInputValue, meta);
      });
    },
  );

  return {
    inputValue,
    setInputValue,
  };
}
